#include <bits/stdc++.h>
using namespace std;

const int N=6e5+10;

int n,m,a[N],s[N],root[N],low[N*24],son[N*24][2],tot;

void add(int root,int lastroot,int val,int t){
    int p=root,q=lastroot;
    for(int i=23;i>=0;i--){
    	son[p][0]=son[q][0];
    	son[p][1]=son[q][1];
        son[p][(val>>i)&1]=++tot;
        p=son[p][(val>>i)&1];
        q=son[q][(val>>i)&1];
        low[p]=t;
    }
}

int ask(int root,int mxt,int val){
    int res=0,p=root;
    for(int i=23;i>=0;i--){
        int num=((val>>i)&1)^1;
        if(son[p][num] && low[son[p][num]]>=mxt)
            p=son[p][num],res+=(1<<i);
        else
            p=son[p][num^1];
    }
    return res;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=0;i<=n;i++){
        if(i)
            s[i]=s[i-1]^a[i];
        add(root[i]=++tot,(i?root[i-1]:0),s[i],i);
    }
    while(m--){
        char op[2];
        int l,r,x;
        scanf("%s",op);
        if(op[0]=='A'){
            scanf("%d",&x);
            a[++n]=x;
			s[n]=s[n-1]^a[n];
            add(root[n]=++tot,root[n-1],s[n],n);
        }else{
            scanf("%d%d%d",&l,&r,&x);
            printf("%d\n",ask(root[r-1],l-1,s[n]^x));
        }
    }
    return 0;
}
